function candidate(expression, payload, config, parsedMeta) {
  if (!expression) {
    return undefined;
  }

  var opts = config || {};
  var limit = typeof opts.depth === 'number' ? opts.depth : 5;
  var text = String(expression);

  if (opts.allowDots) {
    text = text.replace(/\.([^.[\]]+)/g, '[$1]');
  }

  var guarded = Object.prototype.hasOwnProperty;
  var pieces = [];

  if (limit > 0) {
    var firstBracket = text.search(/\[[^[\]]*]/);
    var root = firstBracket >= 0 ? text.slice(0, firstBracket) : text;

    if (root) {
      if (!opts.plainObjects && guarded.call(Object.prototype, root) && !opts.allowPrototypes) {
        return undefined;
      }
      pieces.push(root);
    }

    var matcher = /\[[^[\]]*]/g;
    var match;
    var count = 0;

    while ((match = matcher.exec(text)) !== null && count < limit) {
      var inner = match[0].slice(1, -1);
      if (!opts.plainObjects && guarded.call(Object.prototype, inner) && !opts.allowPrototypes) {
        return undefined;
      }
      pieces.push(match[0]);
      count += 1;
    }

    if (match) {
      pieces.push('[' + text.slice(match.index) + ']');
    }
  } else {
    if (!opts.plainObjects && guarded.call(Object.prototype, text) && !opts.allowPrototypes) {
      return undefined;
    }
    pieces.push(text);
  }

  var build = typeof opts.parseObject === 'function' ? opts.parseObject : candidate.parseObject;
  return build(pieces, payload, opts, parsedMeta);
}

candidate.parseObject = function (segments, value, options, metadata) {
  var opts = options || {};
  var leaf = value;

  for (var i = segments.length - 1; i >= 0; i -= 1) {
    var raw = segments[i];
    var key = raw;
    if (typeof key === 'string' && key.charAt(0) === '[' && key.charAt(key.length - 1) === ']') {
      key = key.slice(1, -1);
    }

    var container;
    if (key === '') {
      container = [];
      container.push(leaf);
    } else if (!opts.parseArrays || !/^\d+$/.test(key)) {
      container = opts.plainObjects ? Object.create(null) : {};
      container[key] = leaf;
    } else {
      container = [];
      container[Number(key)] = leaf;
    }
    leaf = container;
  }

  return leaf;
};
